import { createHooks } from '@belt/ai';

export const hooks = createHooks({
  SessionStart: ({ printInfo }) => {
    printInfo(
      '══════════════════════════════════════════',
      '                BLA BLA                    ',
      '══════════════════════════════════════════',
    );
  },
});

// Other option, export dynamic config

export default ({ dirname, getParentConfig /*...etc*/ }: any) => {
  console.log(dirname, getParentConfig);
