 * Context passed to rule matchers for evaluating conditions
 */
export interface RuleContext {
  /** Tool being invoked (e.g., 'Write', 'Edit', 'Bash') */
  tool: string;
  /** Tool input parameters */
  input: Record<string, any>;
  /** Project root directory */
  projectRoot: string;
}

/**
 * Agent rule definition for blocking, warning, or allowing actions
 */
export interface AgentRule {
  /** Unique identifier for the rule */
  id: string;
  /**
   * Match condition - can be:
   * - string: substring match against file path
   * - RegExp: regex match against file path
   * - function: custom matcher (can be async)
   */
  match: string | RegExp | ((path: string, ctx: RuleContext) => boolean | Promise<boolean>);
  /** Action to take when rule matches */
  action: 'block' | 'warn' | 'allow';
  /** Human-readable message explaining the rule */
  message?: string;
}

/**
 * Context passed to agent hooks
 */
export interface AgentHookContext {
  /** Tool being invoked */
  tool: string;
  /** Tool input parameters */
  input: Record<string, any>;
  /** Project root directory */
  projectRoot: string;
  /** Target file path (if applicable) */
  filePath: string;
  /** Block the action with a message (exit 2) */
  block: (message: string) => void;
  /** Emit a warning but allow the action */
  warn: (message: string) => void;
  /** Inject content into LLM context */
  inject: (content: string) => void;
}

/**
 * Hook handler function type
 */
export type AgentHookHandler<Ctx = AgentHookContext> = (ctx: Ctx) => void | Promise<void>;

/**
 * Agent hooks configuration
 */
export interface AgentHooks {
  /** Called before a tool is used - can block the action */
  PreToolUse?: AgentHookHandler;
  /** Called after a tool is used */
  PostToolUse?: AgentHookHandler;
  /** Called when session starts */
  SessionStart?: AgentHookHandler;
  /** Called when session ends */
  SessionEnd?: AgentHookHandler;
  /** Called on notifications */
  Notification?: AgentHookHandler;
  /** Called when user submits a prompt */
  UserPromptSubmit?: AgentHookHandler;
  /** Called before context compaction */
  PreCompact?: AgentHookHandler;
  /** Called when agent stops */
  Stop?: AgentHookHandler;
  /** Called when subagent stops */
  SubagentStop?: AgentHookHandler;
}

/**
 * Agent configuration object
 */
export interface AgentConfig {
  /** Rules to evaluate on file operations */
  rules?: AgentRule[];
  /** Hook handlers */
  hooks?: AgentHooks;
  /**
   * Extend parent configuration
   * Called with merged parent config, returns final config
   */
  extend?: (parent: AgentConfig) => AgentConfig;
}

/**
 * Define an agent configuration with type safety
 * @param config - Agent configuration object
 * @returns The same config (identity function for type inference)
 */
export function defineAgent(config: AgentConfig): AgentConfig {
  return config;
}

