#!/usr/bin/env bun

/**
 * AgentRC Runner - TypeScript-based cascade rules enforcement
 *
 * This script is called by Claude Code hooks to evaluate .agentrc.ts files
 * in the directory hierarchy and enforce rules/execute hooks.
 *
 * Exit codes:
 *   0 - Action allowed
 *   2 - Action blocked (rule violation)
 *   1 - Runner error
 */

import { resolve, dirname } from 'path';
import { existsSync, readdirSync } from 'fs';
import type { AgentConfig, AgentHookContext, AgentRule, RuleContext } from '../../packages/belt-ai/src';

const DEBUG_LOG = '/tmp/agentrc-runner-debug.log';
const PROJECT_ROOT = process.env.CLAUDE_PROJECT_DIR || process.cwd();

// AgentRC file patterns (in priority order)
const AGENTRC_FILES = ['.agentrc.ts', 'agentrc.ts', '.agentrc.js', 'agentrc.js'];

/**
 * Log debug message to file
 */
function logDebug(message: string): void {
  const timestamp = new Date().toISOString();
  Bun.write(DEBUG_LOG, `[${timestamp}] ${message}\n`, { append: true });
}

/**
 * Find all agentrc files from target directory up to project root
 * Returns array ordered from root to target (for proper inheritance)
 */
async function findAgentrcFiles(startDir: string): Promise<string[]> {
  const files: string[] = [];
  let currentDir = startDir;

  // Normalize - if it's a file path, get the directory
  if (existsSync(currentDir) && !Bun.file(currentDir).size) {
    // It's a file, get parent directory
  }

  while (currentDir.startsWith(PROJECT_ROOT) && currentDir !== '/' && currentDir.length >= PROJECT_ROOT.length) {
    for (const filename of AGENTRC_FILES) {
      const filePath = resolve(currentDir, filename);
      if (existsSync(filePath)) {
        files.push(filePath);
        break; // Only one agentrc per directory
      }
    }
    const parent = dirname(currentDir);
    if (parent === currentDir) break; // Reached filesystem root
    currentDir = parent;
  }

  // Reverse to get root first, then children (for proper inheritance)
  return files.reverse();
}

/**
 * Load and merge configs from agentrc files
 */
async function loadAndMergeConfigs(files: string[]): Promise<AgentConfig> {
  let mergedConfig: AgentConfig = { rules: [], hooks: {} };

  for (const file of files) {
    try {
      logDebug(`Loading: ${file}`);
      const module = await import(file);
      const config: AgentConfig = module.default || module;

      // Handle extend function if provided
      if (typeof config.extend === 'function') {
        mergedConfig = config.extend(mergedConfig);
      } else {
        // Default merge: append rules, override hooks
        if (config.rules) {
          mergedConfig.rules = [...(mergedConfig.rules || []), ...config.rules];
        }
        if (config.hooks) {
          mergedConfig.hooks = { ...mergedConfig.hooks, ...config.hooks };
        }
      }
    } catch (err) {
      logDebug(`Error loading ${file}: ${err}`);
      // Continue with other files
    }
  }

  return mergedConfig;
}

/**
 * Evaluate a rule's match condition
 */
async function evaluateRuleMatch(
  rule: AgentRule,
  filePath: string,
  ctx: RuleContext
): Promise<boolean> {
  const { match } = rule;

  if (typeof match === 'string') {
    return filePath.includes(match);
  }

  if (match instanceof RegExp) {
    return match.test(filePath);
  }

  if (typeof match === 'function') {
    return await match(filePath, ctx);
  }

  return false;
}

/**
 * Main execution
 */
async function main(): Promise<void> {
  logDebug('=== AGENTRC RUNNER START ===');

  // Read stdin JSON from Claude Code hook
  let stdinJson: string;
  try {
    stdinJson = await Bun.stdin.text();
    logDebug(`STDIN: ${stdinJson.substring(0, 200)}...`);
  } catch (err) {
    logDebug(`Error reading stdin: ${err}`);
    process.exit(0); // Allow on stdin error
  }

  // Parse hook input
  let toolName: string;
  let toolInput: Record<string, any>;
  let filePath: string | undefined;

  try {
    const parsed = JSON.parse(stdinJson);
    toolName = parsed.tool_name || 'unknown';
    toolInput = parsed.tool_input || {};
    filePath = toolInput.file_path;
  } catch (err) {
    logDebug(`Error parsing JSON: ${err}`);
    process.exit(0); // Allow on parse error
  }

  logDebug(`Tool: ${toolName}, FilePath: ${filePath || 'none'}`);

  // If no file path, allow action
  if (!filePath) {
    logDebug('No file path, allowing action');
    process.exit(0);
  }

  // Find agentrc files in hierarchy
  const targetDir = dirname(filePath);
  const agentrcFiles = await findAgentrcFiles(targetDir);
  logDebug(`Found ${agentrcFiles.length} agentrc files: ${agentrcFiles.join(', ')}`);

  if (agentrcFiles.length === 0) {
    logDebug('No agentrc files found, allowing action');
    process.exit(0);
  }

  // Load and merge configurations
  const config = await loadAndMergeConfigs(agentrcFiles);
  logDebug(`Merged config: ${config.rules?.length || 0} rules, ${Object.keys(config.hooks || {}).length} hooks`);

  // Create rule context
  const ruleCtx: RuleContext = {
    tool: toolName,
    input: toolInput,
    projectRoot: PROJECT_ROOT,
  };

  // Evaluate rules
  for (const rule of config.rules || []) {
    const matches = await evaluateRuleMatch(rule, filePath, ruleCtx);

    if (matches) {
      logDebug(`Rule ${rule.id} matched with action: ${rule.action}`);

      if (rule.action === 'block') {
        console.error(`\n❌ RULE VIOLATION: ${rule.id}`);
        console.error(`   ${rule.message || 'Action blocked by agentrc rule'}`);
        console.error(`   File: ${filePath}`);
        console.error('');
        process.exit(2);
      }

      if (rule.action === 'warn') {
        console.error(`\n⚠️  WARNING: ${rule.id}`);
        console.error(`   ${rule.message || 'Warning from agentrc rule'}`);
        console.error('');
      }
    }
  }

  // Execute PreToolUse hook if defined
  if (config.hooks?.PreToolUse) {
    let blocked = false;
    let blockMessage = '';
    const injectedContent: string[] = [];

    const hookCtx: AgentHookContext = {
      tool: toolName,
      input: toolInput,
      projectRoot: PROJECT_ROOT,
      filePath,
      block: (msg: string) => {
        blocked = true;
        blockMessage = msg;
      },
      warn: (msg: string) => {
        console.error(`⚠️  ${msg}`);
      },
      inject: (content: string) => {
        injectedContent.push(content);
      },
    };

    try {
      await config.hooks.PreToolUse(hookCtx);
    } catch (err) {
      logDebug(`Hook error: ${err}`);
      // Don't block on hook errors
    }

    // Output injected content
    if (injectedContent.length > 0) {
      console.log(injectedContent.join('\n'));
    }

    if (blocked) {
      console.error(`\n❌ BLOCKED BY HOOK: ${blockMessage}`);
      process.exit(2);
    }
  }

  logDebug(`ALLOWED: ${filePath}`);
  process.exit(0);
}

// Run
main().catch((err) => {
  console.error(`AgentRC Runner error: ${err}`);
  process.exit(1);
});

