import { defineAgent } from './packages/belt-ai/src';

/**
 * Root AgentRC configuration for MMS Last Attempt
 *
 * This file defines rules and hooks that cascade to all subdirectories.
 * Child directories can have their own .agentrc.ts that extends or overrides.
 */
export default defineAgent({
  rules: [
    // Block .forbidden files (test rule)
    {
      id: 'NO-FORBIDDEN-FILES',
      match: (path) => path.endsWith('.forbidden'),
      action: 'block',
      message: 'Cannot create .forbidden files - this extension is blocked by project rules',
    },

    // Warn on sensitive paths
    {
      id: 'SENSITIVE-PATH-WARNING',
      match: /secret|password|credential|\.env/i,
      action: 'warn',
      message: 'Sensitive path detected - ensure no secrets are committed',
    },
  ],

  hooks: {
    PreToolUse: async ({ tool, filePath, inject }) => {
      // Inject context banner
      inject('');
      inject('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
      inject(`🔒 AGENTRC ACTIVE | Tool: ${tool}`);
      inject(`   Path: ${filePath}`);
      inject('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
      inject('');
    },

    SessionStart: ({ inject }) => {
      inject('');
      inject('══════════════════════════════════════════════════════════');
      inject('        🚀 AGENTRC SYSTEM ACTIVE                           ');
      inject('══════════════════════════════════════════════════════════');
      inject('');
    },
  },
});

