  }

  if (config.hooks?.PreToolUse) {
    let blocked = false;
    let blockMessage = '';
    const injectedContent: string[] = [];

    const hookCtx: AgentHookContext = {
      tool: toolName,
      input: toolInput,
      projectRoot: PROJECT_ROOT,
      filePath,
      block: (msg: string) => { blocked = true; blockMessage = msg; },
      warn: (msg: string) => console.error(\`⚠️  \${msg}\`),
      inject: (content: string) => injectedContent.push(content),
    };

    try {
      await config.hooks.PreToolUse(hookCtx);
    } catch (err) {
      logDebug(\`Hook error: \${err}\`);
    }

    if (injectedContent.length > 0) {
      console.log(injectedContent.join('\\n'));
    }

    if (blocked) {
      console.error(\`\\n❌ BLOCKED: \${blockMessage}\`);
      process.exit(2);
    }
  }

  logDebug(\`ALLOWED: \${filePath}\`);
  process.exit(0);
}

main().catch((err) => {
  console.error(\`Runner error: \${err}\`);
  process.exit(1);
});
`,

  wrapper: `#!/bin/bash
# AgentRC Wrapper - Thin bash wrapper for TypeScript runner
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "\${BASH_SOURCE[0]}")" && pwd)"
RUNNER="\${SCRIPT_DIR}/agentrc-runner.ts"

if [[ ! -f "$RUNNER" ]]; then
    echo "ERROR: agentrc-runner.ts not found" >&2
    exit 1
fi

if ! command -v bun &> /dev/null; then
    echo "ERROR: bun is required. Install: curl -fsSL https://bun.sh/install | bash" >&2
    exit 1
fi

exec bun run "$RUNNER"
`,
};

const REQUIRED_HOOKS: ClaudeSettings['hooks'] = {
  PreToolUse: [
    {
      matcher: 'Write',
      hooks: [{ type: 'command', command: 'bash "$CLAUDE_PROJECT_DIR"/.claude/hooks/agentrc-wrapper.sh' }],
    },
    {
      matcher: 'Edit',
      hooks: [{ type: 'command', command: 'bash "$CLAUDE_PROJECT_DIR"/.claude/hooks/agentrc-wrapper.sh' }],
    },
  ],
};

function mergeHooks(
  existing: ClaudeSettings['hooks'] = {},
  required: ClaudeSettings['hooks'] = {}
): ClaudeSettings['hooks'] {
  const merged = { ...existing };

  for (const [hookName, requiredMatchers] of Object.entries(required)) {
    if (!merged[hookName]) {
      merged[hookName] = [];
    }

    for (const requiredMatcher of requiredMatchers) {
      // Check if matcher already exists
      const existingMatcher = merged[hookName].find(
        (m) => m.matcher === requiredMatcher.matcher
      );

      if (existingMatcher) {
        // Merge hooks for this matcher
        for (const hook of requiredMatcher.hooks) {
          const hookExists = existingMatcher.hooks.some(
            (h) => h.command === hook.command
          );
          if (!hookExists) {
            existingMatcher.hooks.push(hook);
          }
        }
      } else {
        // Add new matcher
        merged[hookName].push(requiredMatcher);
      }
    }
  }

  return merged;
}

function setup(targetDir: string): void {
  const projectDir = resolve(targetDir);
  const claudeDir = join(projectDir, '.claude');
  const hooksDir = join(claudeDir, 'hooks');
  const settingsPath = join(claudeDir, 'settings.json');
  const agentrcPath = join(projectDir, '.agentrc.ts');

  console.log('\\n🔧 belt-ai-setup');
  console.log(`   Target: ${projectDir}\\n`);

  // Create directories
  if (!existsSync(claudeDir)) {
    mkdirSync(claudeDir, { recursive: true });
    console.log('✅ Created .claude/');
  }

  if (!existsSync(hooksDir)) {
    mkdirSync(hooksDir, { recursive: true });
    console.log('✅ Created .claude/hooks/');
  }

  // Create or update settings.json
  let settings: ClaudeSettings = {
    $schema: 'https://json.schemastore.org/claude-code-settings.json',
    hooks: {},
  };

  if (existsSync(settingsPath)) {
    try {
      const existing = JSON.parse(readFileSync(settingsPath, 'utf-8'));
      settings = { ...settings, ...existing };
      console.log('📝 Merging existing .claude/settings.json');
    } catch {
      console.log('⚠️  Could not parse existing settings.json, creating new');
    }
  }

  settings.hooks = mergeHooks(settings.hooks, REQUIRED_HOOKS);
  writeFileSync(settingsPath, JSON.stringify(settings, null, 2) + '\\n');
  console.log('✅ Updated .claude/settings.json');

  // Create runner
  const runnerPath = join(hooksDir, 'agentrc-runner.ts');
  writeFileSync(runnerPath, TEMPLATES.runner);
  console.log('✅ Created .claude/hooks/agentrc-runner.ts');

  // Create wrapper
  const wrapperPath = join(hooksDir, 'agentrc-wrapper.sh');
  writeFileSync(wrapperPath, TEMPLATES.wrapper, { mode: 0o755 });
  console.log('✅ Created .claude/hooks/agentrc-wrapper.sh');

  // Create .agentrc.ts if not exists
  if (!existsSync(agentrcPath)) {
    writeFileSync(agentrcPath, TEMPLATES.agentrc);
    console.log('✅ Created .agentrc.ts');
  } else {
    console.log('📝 .agentrc.ts already exists, skipping');
  }

  console.log('\\n✨ AgentRC setup complete!');
  console.log('\\nNext steps:');
  console.log('  1. Edit .agentrc.ts to define your rules and hooks');
  console.log('  2. Start a Claude Code session in this project');
  console.log('  3. Rules will be automatically enforced\\n');
}

// Main
const args = process.argv.slice(2);
const command = args[0];
const targetDir = args[1] || process.cwd();

if (command === 'setup' || !command) {
  setup(targetDir);
} else {
  console.log('Usage: belt-ai setup [directory]');
  process.exit(1);
}

