import { describe, it, expect } from 'vitest';
import { defineAgent } from '../types/agent';
import type { AgentConfig, AgentRule, AgentHooks } from '../types/agent';

describe('defineAgent', () => {
  describe('basic configuration', () => {
    it('should return the same config object (identity function)', () => {
      const config: AgentConfig = {
        rules: [],
        hooks: {},
      };

      const result = defineAgent(config);

      expect(result).toBe(config);
    });

    it('should accept empty config', () => {
      const config: AgentConfig = {};

      const result = defineAgent(config);

      expect(result).toEqual({});
    });

    it('should accept config with only rules', () => {
      const config: AgentConfig = {
        rules: [
          {
            id: 'TEST-001',
            match: '.forbidden',
            action: 'block',
          },
        ],
      };

      const result = defineAgent(config);

      expect(result.rules).toHaveLength(1);
      expect(result.rules![0].id).toBe('TEST-001');
    });

    it('should accept config with only hooks', () => {
      const config: AgentConfig = {
        hooks: {
          PreToolUse: () => {},
          SessionStart: () => {},
        },
      };

      const result = defineAgent(config);

      expect(result.hooks).toBeDefined();
      expect(typeof result.hooks!.PreToolUse).toBe('function');
      expect(typeof result.hooks!.SessionStart).toBe('function');
    });
  });

  describe('rules configuration', () => {
    it('should accept rule with string match', () => {
      const rule: AgentRule = {
        id: 'STRING-MATCH',
        match: '.forbidden',
        action: 'block',
        message: 'Forbidden extension',
      };

      const config = defineAgent({ rules: [rule] });

      expect(config.rules![0].match).toBe('.forbidden');
    });

    it('should accept rule with regex match', () => {
      const rule: AgentRule = {
        id: 'REGEX-MATCH',
        match: /\.secret\./i,
        action: 'warn',
      };

      const config = defineAgent({ rules: [rule] });

      expect(config.rules![0].match).toBeInstanceOf(RegExp);
    });

    it('should accept rule with function match', () => {
      const matchFn = (path: string) => path.endsWith('.forbidden');

      const rule: AgentRule = {
        id: 'FUNCTION-MATCH',
        match: matchFn,
        action: 'block',
      };

      const config = defineAgent({ rules: [rule] });

      expect(typeof config.rules![0].match).toBe('function');
    });

    it('should accept rule with async function match', () => {
      const asyncMatchFn = async (path: string) => {
        await Promise.resolve();
        return path.includes('secret');
      };

      const rule: AgentRule = {
        id: 'ASYNC-MATCH',
