import { describe, it, expect } from 'vitest';
import type { AgentRule, RuleContext } from '../types/agent';

/**
 * Rule matching logic extracted for testing
 * This mirrors the logic in agentrc-runner.ts
 */
async function evaluateRuleMatch(
  rule: AgentRule,
  filePath: string,
  ctx: RuleContext
): Promise<boolean> {
  const { match } = rule;

  if (typeof match === 'string') return filePath.includes(match);
  if (match instanceof RegExp) return match.test(filePath);
  if (typeof match === 'function') return await match(filePath, ctx);

  return false;
}

describe('Rule Matching', () => {
  const defaultContext: RuleContext = {
    tool: 'Write',
    input: { file_path: '/test/path' },
    projectRoot: '/project',
  };

  describe('string matching', () => {
    it('should match substring in path', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: '.forbidden',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/to/file.forbidden', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/to/.forbidden/file', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/to/file.txt', defaultContext)).toBe(false);
    });

    it('should match anywhere in path', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'secret',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/secret/file.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/to/secret.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/to/mysecretfile.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/to/public.txt', defaultContext)).toBe(false);
    });

    it('should be case sensitive', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'Secret',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/Secret/file.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/secret/file.txt', defaultContext)).toBe(false);
      expect(await evaluateRuleMatch(rule, '/path/SECRET/file.txt', defaultContext)).toBe(false);
    });

    it('should match file extensions', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: '.env',
        action: 'warn',
      };

      expect(await evaluateRuleMatch(rule, '/path/.env', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/.env.local', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/.env.production', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/environment.txt', defaultContext)).toBe(false);
    });

    it('should match directory names', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'node_modules',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/node_modules/package/index.js', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/src/file.js', defaultContext)).toBe(false);
    });
  });

  describe('regex matching', () => {
    it('should match with basic regex', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: /\.env$/,
        action: 'warn',
      };

      expect(await evaluateRuleMatch(rule, '/path/.env', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/.env.local', defaultContext)).toBe(false);
    });

    it('should match case insensitive with i flag', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: /secret/i,
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/Secret/file.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/SECRET/file.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/secret/file.txt', defaultContext)).toBe(true);
    });

    it('should match multiple patterns with OR', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: /secret|password|credential/i,
        action: 'warn',
      };

      expect(await evaluateRuleMatch(rule, '/path/secret.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/password.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/credential.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/public.txt', defaultContext)).toBe(false);
    });

    it('should match file extensions with regex', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: /\.(ts|tsx|js|jsx)$/,
        action: 'allow',
      };

      expect(await evaluateRuleMatch(rule, '/path/file.ts', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/file.tsx', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/file.js', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/file.jsx', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/file.css', defaultContext)).toBe(false);
    });

    it('should match specific directory structures', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: /\/src\/components\/.*\.tsx$/,
        action: 'allow',
      };

      expect(await evaluateRuleMatch(rule, '/project/src/components/Button.tsx', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/project/src/utils/helper.tsx', defaultContext)).toBe(false);
      expect(await evaluateRuleMatch(rule, '/project/src/components/Button.ts', defaultContext)).toBe(false);
    });

    it('should match negative lookahead', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: /^(?!.*node_modules).*\.js$/,
        action: 'allow',
      };

      expect(await evaluateRuleMatch(rule, '/project/src/file.js', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/project/node_modules/pkg/file.js', defaultContext)).toBe(false);
    });
  });

  describe('function matching', () => {
    it('should call function with path and context', async () => {
      let receivedPath: string | undefined;
      let receivedCtx: RuleContext | undefined;

      const rule: AgentRule = {
        id: 'TEST',
        match: (path, ctx) => {
          receivedPath = path;
          receivedCtx = ctx;
          return true;
        },
        action: 'block',
      };

      await evaluateRuleMatch(rule, '/test/path.txt', defaultContext);

      expect(receivedPath).toBe('/test/path.txt');
      expect(receivedCtx).toBe(defaultContext);
    });

    it('should handle sync function returning true', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: (path) => path.endsWith('.forbidden'),
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/file.forbidden', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/file.txt', defaultContext)).toBe(false);
    });

    it('should handle sync function returning false', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: () => false,
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/any/path', defaultContext)).toBe(false);
    });

    it('should handle async function', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: async (path) => {
          await new Promise((resolve) => setTimeout(resolve, 10));
          return path.includes('secret');
        },
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/secret/file.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/public/file.txt', defaultContext)).toBe(false);
    });

    it('should have access to tool name in context', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: (_, ctx) => ctx.tool === 'Write',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/any/path', { ...defaultContext, tool: 'Write' })).toBe(true);
      expect(await evaluateRuleMatch(rule, '/any/path', { ...defaultContext, tool: 'Edit' })).toBe(false);
    });

    it('should have access to input in context', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: (_, ctx) => {
          const content = ctx.input.content as string | undefined;
          return content?.includes('TODO') ?? false;
        },
        action: 'warn',
      };

      const ctxWithTodo: RuleContext = {
        ...defaultContext,
        input: { file_path: '/path', content: '// TODO: fix this' },
      };

      const ctxWithoutTodo: RuleContext = {
        ...defaultContext,
        input: { file_path: '/path', content: '// Done' },
      };

      expect(await evaluateRuleMatch(rule, '/path', ctxWithTodo)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path', ctxWithoutTodo)).toBe(false);
    });

    it('should handle complex business logic', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: (path, ctx) => {
          // Block if:
          // 1. Path is in src/
          // 2. Tool is Write (not Edit)
          // 3. File is a test file
          const isInSrc = path.includes('/src/');
          const isWrite = ctx.tool === 'Write';
          const isTest = path.includes('.test.') || path.includes('.spec.');

          return isInSrc && isWrite && isTest;
        },
        action: 'block',
      };

      // Should block: src + Write + test
      expect(
        await evaluateRuleMatch(rule, '/project/src/utils.test.ts', { ...defaultContext, tool: 'Write' })
      ).toBe(true);

      // Should not block: src + Edit + test
      expect(
        await evaluateRuleMatch(rule, '/project/src/utils.test.ts', { ...defaultContext, tool: 'Edit' })
      ).toBe(false);

      // Should not block: not in src
      expect(
        await evaluateRuleMatch(rule, '/project/tests/utils.test.ts', { ...defaultContext, tool: 'Write' })
      ).toBe(false);

      // Should not block: not a test
      expect(
        await evaluateRuleMatch(rule, '/project/src/utils.ts', { ...defaultContext, tool: 'Write' })
      ).toBe(false);
    });
  });

  describe('edge cases', () => {
    it('should handle empty path', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'anything',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '', defaultContext)).toBe(false);
    });

    it('should handle path with special characters', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'file (1)',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/file (1).txt', defaultContext)).toBe(true);
    });

    it('should handle unicode in path', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'arquivo',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/caminho/arquivo.txt', defaultContext)).toBe(true);
    });

    it('should handle very long paths', async () => {
      const longPath = '/a'.repeat(1000) + '/file.txt';
      const rule: AgentRule = {
        id: 'TEST',
        match: 'file.txt',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, longPath, defaultContext)).toBe(true);
    });

    it('should handle regex special characters in string match', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: '[test]',
        action: 'block',
      };

      // String match is literal, not regex
      expect(await evaluateRuleMatch(rule, '/path/[test]/file.txt', defaultContext)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path/t/file.txt', defaultContext)).toBe(false);
    });
  });
});

