      const ctxWithoutTodo: RuleContext = {
        ...defaultContext,
        input: { file_path: '/path', content: '// Done' },
      };

      expect(await evaluateRuleMatch(rule, '/path', ctxWithTodo)).toBe(true);
      expect(await evaluateRuleMatch(rule, '/path', ctxWithoutTodo)).toBe(false);
