  });

  describe('edge cases', () => {
    it('should handle empty path', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'anything',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '', defaultContext)).toBe(false);
    });

    it('should handle path with special characters', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'file (1)',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/path/file (1).txt', defaultContext)).toBe(true);
    });

    it('should handle unicode in path', async () => {
      const rule: AgentRule = {
        id: 'TEST',
        match: 'arquivo',
        action: 'block',
      };

      expect(await evaluateRuleMatch(rule, '/caminho/arquivo.txt', defaultContext)).toBe(true);
