import { describe, it, expect, vi } from 'vitest';
import type { AgentConfig, AgentRule, AgentHooks } from '../types/agent';
import { defineAgent } from '../types/agent';

/**
 * Simulates the config merging logic from agentrc-runner.ts
 */
function mergeConfigs(configs: AgentConfig[]): AgentConfig {
  let mergedConfig: AgentConfig = { rules: [], hooks: {} };

  for (const config of configs) {
    if (typeof config.extend === 'function') {
      mergedConfig = config.extend(mergedConfig);
    } else {
      // Default merge: append rules, override hooks
      if (config.rules) {
        mergedConfig.rules = [...(mergedConfig.rules || []), ...config.rules];
      }
      if (config.hooks) {
        mergedConfig.hooks = { ...mergedConfig.hooks, ...config.hooks };
      }
    }
  }

  return mergedConfig;
}

describe('Cascade Config Merging', () => {
  describe('basic merging', () => {
    it('should merge empty configs', () => {
      const configs: AgentConfig[] = [{}, {}, {}];

      const result = mergeConfigs(configs);

      expect(result.rules).toEqual([]);
      expect(result.hooks).toEqual({});
    });

    it('should merge single config', () => {
      const configs: AgentConfig[] = [
        {
          rules: [{ id: 'RULE-1', match: '.test', action: 'block' }],
          hooks: { PreToolUse: () => {} },
        },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(1);
      expect(result.hooks?.PreToolUse).toBeDefined();
    });

    it('should append rules from multiple configs', () => {
      const configs: AgentConfig[] = [
        { rules: [{ id: 'RULE-1', match: '.a', action: 'block' }] },
        { rules: [{ id: 'RULE-2', match: '.b', action: 'warn' }] },
        { rules: [{ id: 'RULE-3', match: '.c', action: 'allow' }] },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(3);
      expect(result.rules![0].id).toBe('RULE-1');
      expect(result.rules![1].id).toBe('RULE-2');
      expect(result.rules![2].id).toBe('RULE-3');
    });

    it('should override hooks (last wins)', () => {
      const hook1 = vi.fn();
      const hook2 = vi.fn();

      const configs: AgentConfig[] = [
        { hooks: { PreToolUse: hook1 } },
        { hooks: { PreToolUse: hook2 } },
      ];

      const result = mergeConfigs(configs);

      expect(result.hooks?.PreToolUse).toBe(hook2);
    });

    it('should merge different hook types', () => {
      const preHook = vi.fn();
      const postHook = vi.fn();
      const sessionHook = vi.fn();

      const configs: AgentConfig[] = [
        { hooks: { PreToolUse: preHook } },
        { hooks: { PostToolUse: postHook } },
        { hooks: { SessionStart: sessionHook } },
      ];

      const result = mergeConfigs(configs);

      expect(result.hooks?.PreToolUse).toBe(preHook);
      expect(result.hooks?.PostToolUse).toBe(postHook);
      expect(result.hooks?.SessionStart).toBe(sessionHook);
    });
  });

  describe('extend function', () => {
    it('should use extend function when provided', () => {
      const configs: AgentConfig[] = [
        {
          rules: [{ id: 'PARENT', match: '.parent', action: 'block' }],
        },
        {
          extend: (parent) => ({
            rules: [
              ...(parent.rules || []),
              { id: 'CHILD', match: '.child', action: 'warn' },
            ],
          }),
        },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(2);
      expect(result.rules![0].id).toBe('PARENT');
      expect(result.rules![1].id).toBe('CHILD');
    });

    it('should allow extend to filter parent rules', () => {
      const configs: AgentConfig[] = [
        {
          rules: [
            { id: 'KEEP', match: '.keep', action: 'block' },
            { id: 'REMOVE', match: '.remove', action: 'warn' },
          ],
        },
        {
          extend: (parent) => ({
            rules: (parent.rules || []).filter((r) => r.id !== 'REMOVE'),
          }),
        },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(1);
      expect(result.rules![0].id).toBe('KEEP');
    });

    it('should allow extend to modify parent rules', () => {
      const configs: AgentConfig[] = [
        {
          rules: [{ id: 'RULE', match: '.test', action: 'warn' }],
        },
        {
          extend: (parent) => ({
            rules: (parent.rules || []).map((r) => ({
              ...r,
              action: 'block' as const, // Upgrade warn to block
            })),
          }),
        },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules![0].action).toBe('block');
    });

    it('should allow extend to wrap parent hooks', () => {
      const parentHook = vi.fn();
      let hookCalled = false;

      const configs: AgentConfig[] = [
        { hooks: { PreToolUse: parentHook } },
        {
          extend: (parent) => ({
            hooks: {
              PreToolUse: (ctx) => {
                hookCalled = true;
                // Call parent hook first
                parent.hooks?.PreToolUse?.(ctx);
                // Then add child behavior
              },
            },
          }),
        },
      ];

      const result = mergeConfigs(configs);
      result.hooks?.PreToolUse?.({} as any);

      expect(hookCalled).toBe(true);
      expect(parentHook).toHaveBeenCalled();
    });

    it('should allow extend to completely replace config', () => {
      const configs: AgentConfig[] = [
        {
          rules: [{ id: 'PARENT', match: '.parent', action: 'block' }],
          hooks: { PreToolUse: vi.fn() },
        },
        {
          extend: () => ({
            rules: [{ id: 'CHILD-ONLY', match: '.child', action: 'allow' }],
            // No hooks - parent hooks are lost
          }),
        },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(1);
      expect(result.rules![0].id).toBe('CHILD-ONLY');
      expect(result.hooks?.PreToolUse).toBeUndefined();
    });
  });

  describe('directory hierarchy simulation', () => {
    it('should simulate root -> src -> components hierarchy', () => {
      // /project/.agentrc.ts (root)
      const rootConfig: AgentConfig = {
        rules: [
          { id: 'ROOT-NO-ENV', match: '.env', action: 'block' },
          { id: 'ROOT-WARN-SECRET', match: 'secret', action: 'warn' },
        ],
        hooks: {
          SessionStart: ({ inject }) => inject('Root AgentRC'),
        },
      };

      // /project/src/.agentrc.ts
      const srcConfig: AgentConfig = {
        rules: [{ id: 'SRC-TYPESCRIPT', match: '.ts', action: 'allow' }],
        hooks: {
          PreToolUse: ({ inject }) => inject('SRC rules apply'),
        },
      };

      // /project/src/components/.agentrc.ts
      const componentsConfig: AgentConfig = {
        rules: [{ id: 'COMP-NO-INDEX', match: 'index.ts', action: 'block' }],
        extend: (parent) => ({
          rules: [...(parent.rules || []), { id: 'COMP-NO-INDEX', match: 'index.ts', action: 'block' }],
          hooks: {
            ...parent.hooks,
            PreToolUse: ({ inject }) => {
              parent.hooks?.PreToolUse?.({ inject } as any);
              inject('Components rules apply');
            },
          },
        }),
      };

      // Order: root first, then children (as collected by walking up)
      const configs = [rootConfig, srcConfig, componentsConfig];
      const result = mergeConfigs(configs);

      // Should have rules from all levels
      expect(result.rules).toHaveLength(4);
      expect(result.rules!.map((r) => r.id)).toContain('ROOT-NO-ENV');
      expect(result.rules!.map((r) => r.id)).toContain('SRC-TYPESCRIPT');
      expect(result.rules!.map((r) => r.id)).toContain('COMP-NO-INDEX');

      // Hooks should include chain
      expect(result.hooks?.PreToolUse).toBeDefined();
      expect(result.hooks?.SessionStart).toBeDefined();
    });

    it('should respect rule order (root rules first)', () => {
      const rootConfig: AgentConfig = {
        rules: [{ id: 'ROOT', match: 'x', action: 'block' }],
      };

      const childConfig: AgentConfig = {
        rules: [{ id: 'CHILD', match: 'x', action: 'allow' }],
      };

      const result = mergeConfigs([rootConfig, childConfig]);

      // Root rules come first
      expect(result.rules![0].id).toBe('ROOT');
      expect(result.rules![1].id).toBe('CHILD');
    });
  });

  describe('edge cases', () => {
    it('should handle config with only rules', () => {
      const configs: AgentConfig[] = [
        { rules: [{ id: 'A', match: 'a', action: 'block' }] },
        { rules: [{ id: 'B', match: 'b', action: 'block' }] },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(2);
      expect(result.hooks).toEqual({});
    });

    it('should handle config with only hooks', () => {
      const hook1 = vi.fn();
      const hook2 = vi.fn();

      const configs: AgentConfig[] = [
        { hooks: { PreToolUse: hook1 } },
        { hooks: { PostToolUse: hook2 } },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toEqual([]);
      expect(result.hooks?.PreToolUse).toBe(hook1);
      expect(result.hooks?.PostToolUse).toBe(hook2);
    });

    it('should handle duplicate rule IDs (keeps both)', () => {
      const configs: AgentConfig[] = [
        { rules: [{ id: 'SAME-ID', match: '.a', action: 'block' }] },
        { rules: [{ id: 'SAME-ID', match: '.b', action: 'warn' }] },
      ];

      const result = mergeConfigs(configs);

      expect(result.rules).toHaveLength(2);
      expect(result.rules![0].match).toBe('.a');
      expect(result.rules![1].match).toBe('.b');
    });

    it('should handle mixed configs with and without extend', () => {
      const configs: AgentConfig[] = [
        { rules: [{ id: 'A', match: 'a', action: 'block' }] },
