      expect(result.rules!.some((r) => r.id === 'APP-NO-CONSOLE')).toBe(true);
    });

    it('should implement strict subdirectory', () => {
      // Root: permissive
      const root = defineAgent({
        rules: [{ id: 'ROOT-ALLOW-ALL', match: '', action: 'allow' }],
      });

      // secure/: strict
      const secure = defineAgent({
        extend: (parent) => ({
          // Override: block everything, only allow specific files
          rules: [
            { id: 'SECURE-BLOCK-ALL', match: '', action: 'block', message: 'Secure dir - restricted' },
            { id: 'SECURE-ALLOW-README', match: 'README.md', action: 'allow' },
          ],
          hooks: parent.hooks,
        }),
      });

      const result = mergeConfigs([root, secure]);

      // Extend completely replaced parent rules
      expect(result.rules).toHaveLength(2);
      expect(result.rules![0].id).toBe('SECURE-BLOCK-ALL');
    });
  });
});

