/**
 * Integration Test Utilities
 *
 * Creates real temporary projects and executes Claude Code against them.
 */

import { spawn, execSync } from 'child_process';
import { mkdirSync, writeFileSync, rmSync, existsSync, readFileSync } from 'fs';
import { join, resolve } from 'path';
import { tmpdir } from 'os';
import { randomBytes } from 'crypto';

export type ProjectStructure = {
  [path: string]: string | ProjectStructure;
};

export type ClaudeCodeResult = {
  exitCode: number;
  stdout: string;
  stderr: string;
  error?: Error;
};

export type TestProject = {
  root: string;
  cleanup: () => void;
  runClaudeCode: (prompt: string, options?: ClaudeCodeOptions) => Promise<ClaudeCodeResult>;
  runAgentrcRunner: (toolName: string, filePath: string) => Promise<ClaudeCodeResult>;
  writeFile: (relativePath: string, content: string) => void;
  readFile: (relativePath: string) => string;
  fileExists: (relativePath: string) => boolean;
  createDir: (relativePath: string) => void;
};

export type ClaudeCodeOptions = {
  timeout?: number;
  cwd?: string;
  env?: Record<string, string>;
};

/**
 * Creates a temporary test project with the given structure
 */
export function createTestProject(
  name: string,
  structure: ProjectStructure = {}
): TestProject {
  const uniqueId = randomBytes(4).toString('hex');
  const root = join(tmpdir(), `belt-ai-test-${name}-${uniqueId}`);

  // Create root directory
  mkdirSync(root, { recursive: true });

  // Write structure recursively
  function writeStructure(basePath: string, struct: ProjectStructure) {
    for (const [key, value] of Object.entries(struct)) {
      const fullPath = join(basePath, key);

      if (typeof value === 'string') {
        // It's a file
        const dir = resolve(fullPath, '..');
        mkdirSync(dir, { recursive: true });
        writeFileSync(fullPath, value);
      } else {
        // It's a directory
        mkdirSync(fullPath, { recursive: true });
        writeStructure(fullPath, value);
      }
    }
  }

  writeStructure(root, structure);

  const cleanup = () => {
    try {
      rmSync(root, { recursive: true, force: true });
    } catch {
      // Ignore cleanup errors
    }
  };

  const writeFile = (relativePath: string, content: string) => {
    const fullPath = join(root, relativePath);
    const dir = resolve(fullPath, '..');
    mkdirSync(dir, { recursive: true });
    writeFileSync(fullPath, content);
  };

  const readFile = (relativePath: string) => {
    return readFileSync(join(root, relativePath), 'utf-8');
  };

  const fileExists = (relativePath: string) => {
    return existsSync(join(root, relativePath));
  };

  const createDir = (relativePath: string) => {
    mkdirSync(join(root, relativePath), { recursive: true });
  };

  /**
   * Run Claude Code with a prompt in this project
   */
  const runClaudeCode = async (
    prompt: string,
    options: ClaudeCodeOptions = {}
  ): Promise<ClaudeCodeResult> => {
    const { timeout = 60000, cwd = root, env = {} } = options;

    return new Promise((resolve) => {
      const proc = spawn('claude', ['--print', '--dangerously-skip-permissions', prompt], {
        cwd,
        env: {
          ...process.env,
          ...env,
          CLAUDE_PROJECT_DIR: root,
        },
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      let stdout = '';
      let stderr = '';

      proc.stdout.on('data', (data) => {
        stdout += data.toString();
      });

      proc.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      const timeoutId = setTimeout(() => {
        proc.kill('SIGTERM');
        resolve({
          exitCode: -1,
          stdout,
          stderr: stderr + '\n[TIMEOUT]',
          error: new Error('Process timed out'),
        });
      }, timeout);

      proc.on('close', (code) => {
        clearTimeout(timeoutId);
        resolve({
          exitCode: code ?? 0,
          stdout,
          stderr,
        });
      });

      proc.on('error', (error) => {
        clearTimeout(timeoutId);
        resolve({
          exitCode: -1,
          stdout,
          stderr,
          error,
        });
      });
    });
  };

  /**
   * Run the agentrc-runner directly (simulating what Claude Code hooks do)
   */
  const runAgentrcRunner = async (
    toolName: string,
    filePath: string
  ): Promise<ClaudeCodeResult> => {
    const runnerPath = join(root, '.claude/hooks/agentrc-runner.ts');

    if (!existsSync(runnerPath)) {
      return {
        exitCode: -1,
        stdout: '',
        stderr: 'Runner not found',
        error: new Error('agentrc-runner.ts not found'),
      };
    }

    const stdinJson = JSON.stringify({
      tool_name: toolName,
      tool_input: {
        file_path: join(root, filePath),
      },
    });

    return new Promise((resolve) => {
      const proc = spawn('bun', ['run', runnerPath], {
        cwd: root,
        env: {
          ...process.env,
          CLAUDE_PROJECT_DIR: root,
        },
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      let stdout = '';
      let stderr = '';

      proc.stdout.on('data', (data) => {
        stdout += data.toString();
      });

      proc.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      // Send stdin
      proc.stdin.write(stdinJson);
      proc.stdin.end();

      proc.on('close', (code) => {
        resolve({
          exitCode: code ?? 0,
          stdout,
          stderr,
        });
      });

      proc.on('error', (error) => {
        resolve({
          exitCode: -1,
          stdout,
          stderr,
          error,
        });
      });
    });
  };

  return {
    root,
    cleanup,
    runClaudeCode,
    runAgentrcRunner,
    writeFile,
    readFile,
    fileExists,
    createDir,
  };
}

/**
 * Check if Claude Code CLI is available
 */
export function isClaudeCodeAvailable(): boolean {
  try {
    execSync('which claude', { stdio: 'ignore' });
    return true;
  } catch {
    return false;
  }
}

/**
 * Check if bun is available
 */
export function isBunAvailable(): boolean {
  try {
    execSync('which bun', { stdio: 'ignore' });
    return true;
  } catch {
    return false;
  }
}

/**
 * Default .agentrc.ts content for testing
 */
export const DEFAULT_AGENTRC = `
import { defineAgent } from '@belt/ai';

export default defineAgent({
  rules: [
    {
      id: 'NO-FORBIDDEN-FILES',
      match: (path) => path.endsWith('.forbidden'),
      action: 'block',
      message: 'Cannot create .forbidden files',
    },
    {
      id: 'WARN-SENSITIVE',
      match: /secret|password|credential/i,
      action: 'warn',
      message: 'Sensitive path detected',
    },
  ],
  hooks: {
    PreToolUse: ({ tool, filePath, inject }) => {
      inject(\`[TEST] Tool: \${tool}, Path: \${filePath}\`);
    },
  },
});
`;

/**
 * Default agentrc-runner.ts content (copied from setup)
 */
export const DEFAULT_RUNNER = `#!/usr/bin/env bun

import { resolve, dirname } from 'path';
import { existsSync } from 'fs';

type AgentRule = {
  id: string;
  match: string | RegExp | ((path: string, ctx: any) => boolean | Promise<boolean>);
  action: 'block' | 'warn' | 'allow';
  message?: string;
};

type AgentConfig = {
  rules?: AgentRule[];
  hooks?: Record<string, Function>;
  extend?: (parent: AgentConfig) => AgentConfig;
};

const DEBUG_LOG = '/tmp/agentrc-runner-debug.log';
const PROJECT_ROOT = process.env.CLAUDE_PROJECT_DIR || process.cwd();
const AGENTRC_FILES = ['.agentrc.ts', 'agentrc.ts', '.agentrc.js', 'agentrc.js'];

function logDebug(message: string): void {
  const timestamp = new Date().toISOString();
  Bun.write(DEBUG_LOG, \`[\${timestamp}] \${message}\\n\`, { append: true });
}

async function findAgentrcFiles(startDir: string): Promise<string[]> {
  const files: string[] = [];
  let currentDir = startDir;

  while (currentDir.startsWith(PROJECT_ROOT) && currentDir !== '/' && currentDir.length >= PROJECT_ROOT.length) {
    for (const filename of AGENTRC_FILES) {
      const filePath = resolve(currentDir, filename);
      if (existsSync(filePath)) {
        files.push(filePath);
        break;
      }
    }
    const parent = dirname(currentDir);
    if (parent === currentDir) break;
    currentDir = parent;
  }

  return files.reverse();
}

async function loadAndMergeConfigs(files: string[]): Promise<AgentConfig> {
  let mergedConfig: AgentConfig = { rules: [], hooks: {} };

  for (const file of files) {
    try {
      logDebug(\`Loading: \${file}\`);
      const module = await import(file);
      const config: AgentConfig = module.default || module;

      if (typeof config.extend === 'function') {
        mergedConfig = config.extend(mergedConfig);
      } else {
        if (config.rules) {
          mergedConfig.rules = [...(mergedConfig.rules || []), ...config.rules];
        }
        if (config.hooks) {
          mergedConfig.hooks = { ...mergedConfig.hooks, ...config.hooks };
        }
      }
    } catch (err) {
      logDebug(\`Error loading \${file}: \${err}\`);
    }
  }

  return mergedConfig;
}

async function evaluateRuleMatch(rule: AgentRule, filePath: string, ctx: any): Promise<boolean> {
  const { match } = rule;
  if (typeof match === 'string') return filePath.includes(match);
  if (match instanceof RegExp) return match.test(filePath);
  if (typeof match === 'function') return await match(filePath, ctx);
  return false;
}

async function main(): Promise<void> {
  logDebug('=== AGENTRC RUNNER START ===');

  let stdinJson: string;
  try {
    stdinJson = await Bun.stdin.text();
    logDebug(\`STDIN: \${stdinJson.substring(0, 200)}...\`);
  } catch {
    process.exit(0);
  }

  let toolName: string;
  let toolInput: Record<string, unknown>;
  let filePath: string | undefined;

  try {
    const parsed = JSON.parse(stdinJson);
    toolName = parsed.tool_name || 'unknown';
    toolInput = parsed.tool_input || {};
    filePath = toolInput.file_path as string | undefined;
  } catch {
    process.exit(0);
  }

  logDebug(\`Tool: \${toolName}, FilePath: \${filePath || 'none'}\`);

  if (!filePath) {
    process.exit(0);
  }

  const targetDir = dirname(filePath);
  const agentrcFiles = await findAgentrcFiles(targetDir);
  logDebug(\`Found \${agentrcFiles.length} agentrc files\`);

  if (agentrcFiles.length === 0) {
    process.exit(0);
  }

  const config = await loadAndMergeConfigs(agentrcFiles);

  const ruleCtx = { tool: toolName, input: toolInput, projectRoot: PROJECT_ROOT };

  for (const rule of config.rules || []) {
    const matches = await evaluateRuleMatch(rule, filePath, ruleCtx);

    if (matches) {
      logDebug(\`Rule \${rule.id} matched: \${rule.action}\`);

      if (rule.action === 'block') {
        console.error(\`\\n❌ RULE VIOLATION: \${rule.id}\`);
        console.error(\`   \${rule.message || 'Action blocked'}\`);
        console.error(\`   File: \${filePath}\\n\`);
        process.exit(2);
      }

      if (rule.action === 'warn') {
        console.error(\`\\n⚠️  WARNING: \${rule.id}\`);
        console.error(\`   \${rule.message || 'Warning'}\\n\`);
      }
    }
  }

  if (config.hooks?.PreToolUse) {
    let blocked = false;
    let blockMessage = '';
    const injectedContent: string[] = [];

    const hookCtx = {
      tool: toolName,
      input: toolInput,
      projectRoot: PROJECT_ROOT,
      filePath,
      block: (msg: string) => { blocked = true; blockMessage = msg; },
      warn: (msg: string) => console.error(\`⚠️  \${msg}\`),
      inject: (content: string) => injectedContent.push(content),
    };

    try {
      await config.hooks.PreToolUse(hookCtx);
    } catch (err) {
      logDebug(\`Hook error: \${err}\`);
    }

    if (injectedContent.length > 0) {
      console.log(injectedContent.join('\\n'));
    }

    if (blocked) {
      console.error(\`\\n❌ BLOCKED: \${blockMessage}\`);
      process.exit(2);
    }
  }

  logDebug(\`ALLOWED: \${filePath}\`);
  process.exit(0);
}

main().catch((err) => {
  console.error(\`Runner error: \${err}\`);
  process.exit(1);
});
`;

/**
 * Default wrapper script
 */
export const DEFAULT_WRAPPER = `#!/bin/bash
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "\${BASH_SOURCE[0]}")" && pwd)"
RUNNER="\${SCRIPT_DIR}/agentrc-runner.ts"
