/**
 * Integration Tests - AgentRC Runner
 *
 * These tests create real temporary projects and execute the agentrc-runner
 * to verify the complete flow works as expected.
 */

import { describe, it, expect, beforeAll, afterAll, beforeEach, afterEach } from 'vitest';
import { execSync } from 'child_process';
import {
  createTestProject,
  createConfiguredTestProject,
  isBunAvailable,
  DEFAULT_AGENTRC,
  DEFAULT_RUNNER,
  DEFAULT_WRAPPER,
  type TestProject,
} from './test-utils';

describe('AgentRC Runner Integration', () => {
  let bunAvailable: boolean;

  beforeAll(() => {
    bunAvailable = isBunAvailable();
    if (!bunAvailable) {
      console.warn('⚠️ Bun not available, some tests will be skipped');
    }
  });

  describe('blocking rules', () => {
    let project: TestProject;

    beforeEach(() => {
      project = createConfiguredTestProject('block-test');
    });

    afterEach(() => {
      project.cleanup();
    });

    it('should block .forbidden files with exit code 2', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'test.forbidden');

      expect(result.exitCode).toBe(2);
      expect(result.stderr).toContain('RULE VIOLATION');
      expect(result.stderr).toContain('NO-FORBIDDEN-FILES');
      expect(result.stderr).toContain('.forbidden');
    });

    it('should block nested .forbidden files', async () => {
      if (!bunAvailable) return;

      project.createDir('src/deep/nested');
      const result = await project.runAgentrcRunner('Write', 'src/deep/nested/file.forbidden');

      expect(result.exitCode).toBe(2);
      expect(result.stderr).toContain('NO-FORBIDDEN-FILES');
    });

    it('should allow regular files', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'src/component.ts');

      expect(result.exitCode).toBe(0);
      expect(result.stderr).not.toContain('RULE VIOLATION');
    });

    it('should block with custom rule message', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'test.forbidden');

      expect(result.stderr).toContain('Cannot create .forbidden files');
    });
  });

  describe('warning rules', () => {
    let project: TestProject;

    beforeEach(() => {
      project = createConfiguredTestProject('warn-test');
    });

    afterEach(() => {
      project.cleanup();
    });

    it('should warn on sensitive paths but allow (exit 0)', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'config/secret.json');

      expect(result.exitCode).toBe(0);
      expect(result.stderr).toContain('WARNING');
      expect(result.stderr).toContain('WARN-SENSITIVE');
      expect(result.stderr).toContain('Sensitive path detected');
    });

    it('should warn on password files', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'passwords.txt');

      expect(result.exitCode).toBe(0);
      expect(result.stderr).toContain('WARNING');
    });

    it('should warn on credential files', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'credentials.json');

      expect(result.exitCode).toBe(0);
      expect(result.stderr).toContain('WARNING');
    });

    it('should not warn on normal files', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'src/utils.ts');

      expect(result.exitCode).toBe(0);
      expect(result.stderr).not.toContain('WARNING');
    });
  });

  describe('hook execution', () => {
    let project: TestProject;

    beforeEach(() => {
      project = createConfiguredTestProject('hook-test');
    });

    afterEach(() => {
      project.cleanup();
    });

    it('should execute PreToolUse hook and inject content', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'src/file.ts');

      expect(result.exitCode).toBe(0);
      expect(result.stdout).toContain('[TEST] Tool: Write');
      expect(result.stdout).toContain('src/file.ts');
    });

    it('should pass correct tool name to hook', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Edit', 'src/file.ts');

      expect(result.stdout).toContain('Tool: Edit');
    });
  });

  describe('cascade hierarchy', () => {
    let project: TestProject;

    beforeEach(() => {
      project = createConfiguredTestProject('cascade-test');
    });

    afterEach(() => {
      project.cleanup();
    });

    it('should load root .agentrc.ts for root files', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'root-file.ts');

      expect(result.exitCode).toBe(0);
      expect(result.stdout).toContain('[TEST]');
    });

    it('should load root .agentrc.ts for nested files', async () => {
      if (!bunAvailable) return;

      project.createDir('src/deep/nested');
      const result = await project.runAgentrcRunner('Write', 'src/deep/nested/file.ts');

      expect(result.exitCode).toBe(0);
      expect(result.stdout).toContain('[TEST]');
    });

    it('should merge child .agentrc.ts with parent', async () => {
      if (!bunAvailable) return;

      // Create child .agentrc.ts that adds a rule
      project.writeFile(
        'src/.agentrc.ts',
        `
import { defineAgent } from '@belt/ai';

export default defineAgent({
  rules: [
    {
      id: 'SRC-NO-INDEX',
      match: 'index.ts',
      action: 'block',
      message: 'No index.ts in src',
    },
  ],
  hooks: {
    PreToolUse: ({ inject }) => {
      inject('[SRC] Child hook executed');
    },
  },
});
`
      );

      // Should block index.ts in src (child rule)
      const indexResult = await project.runAgentrcRunner('Write', 'src/index.ts');
      expect(indexResult.exitCode).toBe(2);
      expect(indexResult.stderr).toContain('SRC-NO-INDEX');

      // Should still block .forbidden (parent rule)
      const forbiddenResult = await project.runAgentrcRunner('Write', 'src/test.forbidden');
      expect(forbiddenResult.exitCode).toBe(2);
      expect(forbiddenResult.stderr).toContain('NO-FORBIDDEN-FILES');
    });

    it('should allow child to extend parent config', async () => {
      if (!bunAvailable) return;

      project.writeFile(
        'src/.agentrc.ts',
        `
import { defineAgent } from '@belt/ai';

export default defineAgent({
  extend: (parent) => ({
    rules: [
      ...(parent.rules || []),
