/**
 * Integration Tests - Setup CLI
 *
 * Tests the belt-ai setup command by creating real temporary directories
 * and verifying files are created correctly.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { execSync } from 'child_process';
import { join, resolve } from 'path';
import { existsSync, readFileSync, statSync } from 'fs';
import { createTestProject, type TestProject } from './test-utils';

// Path to the built setup CLI
const SETUP_CLI = resolve(__dirname, '../../../dist/setup.mjs');

describe('Setup CLI Integration', () => {
  describe('empty project setup', () => {
    let project: TestProject;

    beforeEach(() => {
      project = createTestProject('setup-empty', {
        // Empty project, just a placeholder file
        '.gitkeep': '',
      });
    });

    afterEach(() => {
      project.cleanup();
    });

    it('should create .claude directory', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      expect(project.fileExists('.claude')).toBe(true);
      expect(statSync(join(project.root, '.claude')).isDirectory()).toBe(true);
    });

    it('should create .claude/hooks directory', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      expect(project.fileExists('.claude/hooks')).toBe(true);
      expect(statSync(join(project.root, '.claude/hooks')).isDirectory()).toBe(true);
    });

    it('should create .claude/settings.json', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      expect(project.fileExists('.claude/settings.json')).toBe(true);

      const settings = JSON.parse(project.readFile('.claude/settings.json'));
      expect(settings.$schema).toBe('https://json.schemastore.org/claude-code-settings.json');
      expect(settings.hooks).toBeDefined();
    });

    it('should create settings with PreToolUse hooks', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      const settings = JSON.parse(project.readFile('.claude/settings.json'));

      expect(settings.hooks.PreToolUse).toBeDefined();
      expect(settings.hooks.PreToolUse.length).toBeGreaterThanOrEqual(2);

      const writeHook = settings.hooks.PreToolUse.find((h: any) => h.matcher === 'Write');
      const editHook = settings.hooks.PreToolUse.find((h: any) => h.matcher === 'Edit');

      expect(writeHook).toBeDefined();
      expect(editHook).toBeDefined();
      expect(writeHook.hooks[0].command).toContain('agentrc-wrapper.sh');
    });

    it('should create .claude/hooks/agentrc-runner.ts', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      expect(project.fileExists('.claude/hooks/agentrc-runner.ts')).toBe(true);

      const content = project.readFile('.claude/hooks/agentrc-runner.ts');
      expect(content).toContain('#!/usr/bin/env bun');
      expect(content).toContain('AGENTRC_FILES');
      expect(content).toContain('evaluateRuleMatch');
    });

    it('should create .claude/hooks/agentrc-wrapper.sh', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      expect(project.fileExists('.claude/hooks/agentrc-wrapper.sh')).toBe(true);

      const content = project.readFile('.claude/hooks/agentrc-wrapper.sh');
      expect(content).toContain('#!/bin/bash');
      expect(content).toContain('agentrc-runner.ts');
    });

    it('should make wrapper executable', () => {
      execSync(`node "${SETUP_CLI}" setup "${project.root}"`, { stdio: 'pipe' });

      const wrapperPath = join(project.root, '.claude/hooks/agentrc-wrapper.sh');
      const stats = statSync(wrapperPath);

      // Check if executable bit is set (mode & 0o111)
