/**
 * Integration Test Utilities
 *
 * Creates real temporary projects and executes Claude Code against them.
 */

import { spawn, execSync } from 'child_process';
import { mkdirSync, writeFileSync, rmSync, existsSync, readFileSync } from 'fs';
import { join, resolve } from 'path';
import { tmpdir } from 'os';
import { randomBytes } from 'crypto';

export type ProjectStructure = {
  [path: string]: string | ProjectStructure;
};

export type ClaudeCodeResult = {
  exitCode: number;
  stdout: string;
  stderr: string;
  error?: Error;
};

export type TestProject = {
  root: string;
  cleanup: () => void;
  runClaudeCode: (prompt: string, options?: ClaudeCodeOptions) => Promise<ClaudeCodeResult>;
  runAgentrcRunner: (toolName: string, filePath: string) => Promise<ClaudeCodeResult>;
  writeFile: (relativePath: string, content: string) => void;
  readFile: (relativePath: string) => string;
  fileExists: (relativePath: string) => boolean;
  createDir: (relativePath: string) => void;
};

export type ClaudeCodeOptions = {
  timeout?: number;
  cwd?: string;
  env?: Record<string, string>;
};

/**
 * Creates a temporary test project with the given structure
 */
export function createTestProject(
  name: string,
  structure: ProjectStructure = {}
): TestProject {
  const uniqueId = randomBytes(4).toString('hex');
  const root = join(tmpdir(), `belt-ai-test-${name}-${uniqueId}`);

  // Create root directory
  mkdirSync(root, { recursive: true });

  // Write structure recursively
  function writeStructure(basePath: string, struct: ProjectStructure) {
    for (const [key, value] of Object.entries(struct)) {
      const fullPath = join(basePath, key);

      if (typeof value === 'string') {
        // It's a file
        const dir = resolve(fullPath, '..');
        mkdirSync(dir, { recursive: true });
        writeFileSync(fullPath, value);
      } else {
        // It's a directory
        mkdirSync(fullPath, { recursive: true });
        writeStructure(fullPath, value);
      }
    }
  }

  writeStructure(root, structure);

  const cleanup = () => {
    try {
      rmSync(root, { recursive: true, force: true });
    } catch {
      // Ignore cleanup errors
    }
  };

  const writeFile = (relativePath: string, content: string) => {
    const fullPath = join(root, relativePath);
    const dir = resolve(fullPath, '..');
    mkdirSync(dir, { recursive: true });
    writeFileSync(fullPath, content);
  };

  const readFile = (relativePath: string) => {
    return readFileSync(join(root, relativePath), 'utf-8');
  };

  const fileExists = (relativePath: string) => {
    return existsSync(join(root, relativePath));
  };

  const createDir = (relativePath: string) => {
    mkdirSync(join(root, relativePath), { recursive: true });
  };

  /**
   * Run Claude Code with a prompt in this project
   */
  const runClaudeCode = async (
    prompt: string,
    options: ClaudeCodeOptions = {}
  ): Promise<ClaudeCodeResult> => {
    const { timeout = 60000, cwd = root, env = {} } = options;

    return new Promise((resolve) => {
      const proc = spawn('claude', ['--print', '--dangerously-skip-permissions', prompt], {
        cwd,
        env: {
          ...process.env,
          ...env,
          CLAUDE_PROJECT_DIR: root,
        },
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      let stdout = '';
      let stderr = '';

      proc.stdout.on('data', (data) => {
        stdout += data.toString();
      });

      proc.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      const timeoutId = setTimeout(() => {
        proc.kill('SIGTERM');
        resolve({
          exitCode: -1,
          stdout,
          stderr: stderr + '\n[TIMEOUT]',
          error: new Error('Process timed out'),
        });
      }, timeout);

      proc.on('close', (code) => {
        clearTimeout(timeoutId);
        resolve({
          exitCode: code ?? 0,
          stdout,
          stderr,
        });
      });

      proc.on('error', (error) => {
        clearTimeout(timeoutId);
        resolve({
          exitCode: -1,
          stdout,
          stderr,
          error,
        });
      });
    });
  };

  /**
   * Run the agentrc-runner directly (simulating what Claude Code hooks do)
   */
  const runAgentrcRunner = async (
    toolName: string,
    filePath: string
  ): Promise<ClaudeCodeResult> => {
    const runnerPath = join(root, '.claude/hooks/agentrc-runner.ts');

    if (!existsSync(runnerPath)) {
      return {
        exitCode: -1,
        stdout: '',
        stderr: 'Runner not found',
        error: new Error('agentrc-runner.ts not found'),
      };
    }

    const stdinJson = JSON.stringify({
      tool_name: toolName,
      tool_input: {
        file_path: join(root, filePath),
      },
    });

    return new Promise((resolve) => {
      const proc = spawn('bun', ['run', runnerPath], {
        cwd: root,
        env: {
          ...process.env,
          CLAUDE_PROJECT_DIR: root,
        },
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      let stdout = '';
      let stderr = '';

      proc.stdout.on('data', (data) => {
        stdout += data.toString();
      });

      proc.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      // Send stdin
      proc.stdin.write(stdinJson);
      proc.stdin.end();

      proc.on('close', (code) => {
        resolve({
          exitCode: code ?? 0,
          stdout,
          stderr,
        });
      });

      proc.on('error', (error) => {
        resolve({
          exitCode: -1,
          stdout,
          stderr,
          error,
        });
      });
    });
  };

  return {
    root,
    cleanup,
    runClaudeCode,
    runAgentrcRunner,
    writeFile,
    readFile,
    fileExists,
    createDir,
  };
}

