/**
 * Integration Tests - AgentRC Runner
 *
 * These tests create real temporary projects and execute the agentrc-runner
 * to verify the complete flow works as expected.
 */

import { describe, it, expect, beforeAll, afterAll, beforeEach, afterEach } from 'vitest';
import { execSync } from 'child_process';
import {
  createTestProject,
  createConfiguredTestProject,
  isBunAvailable,
  DEFAULT_AGENTRC,
  DEFAULT_RUNNER,
  DEFAULT_WRAPPER,
  type TestProject,
} from './test-utils';

describe('AgentRC Runner Integration', () => {
  let bunAvailable: boolean;

  beforeAll(() => {
    bunAvailable = isBunAvailable();
    if (!bunAvailable) {
      console.warn('⚠️ Bun not available, some tests will be skipped');
    }
  });

  describe('blocking rules', () => {
    let project: TestProject;

    beforeEach(() => {
      project = createConfiguredTestProject('block-test');
    });

    afterEach(() => {
      project.cleanup();
    });

    it('should block .forbidden files with exit code 2', async () => {
      if (!bunAvailable) return;

      const result = await project.runAgentrcRunner('Write', 'test.forbidden');

      expect(result.exitCode).toBe(2);
      expect(result.stderr).toContain('RULE VIOLATION');
      expect(result.stderr).toContain('NO-FORBIDDEN-FILES');
      expect(result.stderr).toContain('.forbidden');
    });

    it('should block nested .forbidden files', async () => {
      if (!bunAvailable) return;

      project.createDir('src/deep/nested');
      const result = await project.runAgentrcRunner('Write', 'src/deep/nested/file.forbidden');

      expect(result.exitCode).toBe(2);
      expect(result.stderr).toContain('NO-FORBIDDEN-FILES');
    });

