# Teste manual rápido para ver o output do Claude
TEMP_DIR=$(mktemp -d)

# Criar estrutura completa
mkdir -p "$TEMP_DIR/.claude/hooks"

cat > "$TEMP_DIR/.agentrc.ts" << 'EOF'
export default {
  rules: [
    {
      id: 'WARN-SENSITIVE',
      match: /secret|password/i,
      action: 'warn',
      message: 'Sensitive path detected',
    },
  ],
  hooks: {
    PreToolUse: ({ inject }) => {
      inject('[TEST] Hook executed!');
    },
  },
};
EOF

# Runner
cat > "$TEMP_DIR/.claude/hooks/agentrc-runner.ts" << 'RUNNER'
#!/usr/bin/env bun
import { resolve, dirname } from 'path';
import { existsSync } from 'fs';

const PROJECT_ROOT = process.env.CLAUDE_PROJECT_DIR || process.cwd();
const AGENTRC_FILES = ['.agentrc.ts', 'agentrc.ts', '.agentrc.js', 'agentrc.js'];

async function findAgentrcFiles(startDir) {
  const files = [];
  let currentDir = startDir;
  while (currentDir.startsWith(PROJECT_ROOT) && currentDir !== '/' && currentDir.length >= PROJECT_ROOT.length) {
    for (const filename of AGENTRC_FILES) {
      const filePath = resolve(currentDir, filename);
      if (existsSync(filePath)) { files.push(filePath); break; }
    }
    const parent = dirname(currentDir);
    if (parent === currentDir) break;
    currentDir = parent;
  }
  return files.reverse();
}

async function main() {
  const stdinJson = await Bun.stdin.text();
  const { tool_name, tool_input } = JSON.parse(stdinJson);
  const filePath = tool_input?.file_path;
  if (!filePath) process.exit(0);

  const targetDir = dirname(filePath);
  const agentrcFiles = await findAgentrcFiles(targetDir);
  if (agentrcFiles.length === 0) process.exit(0);

  let config = { rules: [], hooks: {} };
  for (const file of agentrcFiles) {
    const module = await import(file);
    const c = module.default || module;
    if (c.rules) config.rules = [...config.rules, ...c.rules];
    if (c.hooks) config.hooks = { ...config.hooks, ...c.hooks };
  }

  for (const rule of config.rules || []) {
    let matches = false;
    if (typeof rule.match === 'string') matches = filePath.includes(rule.match);
    else if (rule.match instanceof RegExp) matches = rule.match.test(filePath);
    else if (typeof rule.match === 'function') matches = await rule.match(filePath, {});

    if (matches && rule.action === 'block') {
      console.error(`\n❌ RULE VIOLATION: ${rule.id}\n   ${rule.message}\n   File: ${filePath}\n`);
      process.exit(2);
    }
    if (matches && rule.action === 'warn') {
      console.error(`\n⚠️  WARNING: ${rule.id}\n   ${rule.message}\n`);
    }
  }

  if (config.hooks?.PreToolUse) {
    const injected = [];
    await config.hooks.PreToolUse({
      tool: tool_name,
      input: tool_input,
      projectRoot: PROJECT_ROOT,
      filePath,
      block: (msg) => {},
      warn: (msg) => console.error(`⚠️  ${msg}`),
      inject: (content) => injected.push(content),
    });
    if (injected.length > 0) console.log(injected.join('\n'));
  }

  process.exit(0);
}
main();
RUNNER

cat > "$TEMP_DIR/.claude/hooks/agentrc-wrapper.sh" << 'WRAPPER'
#!/bin/bash
exec bun run "$CLAUDE_PROJECT_DIR/.claude/hooks/agentrc-runner.ts"
WRAPPER
chmod +x "$TEMP_DIR/.claude/hooks/agentrc-wrapper.sh"

cat > "$TEMP_DIR/.claude/settings.json" << 'SETTINGS'
{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Write",
        "hooks": [{ "type": "command", "command": "bash \"$CLAUDE_PROJECT_DIR\"/.claude/hooks/agentrc-wrapper.sh" }]
      }
    ]
  }
}
SETTINGS

echo "=== Testando runner diretamente ==="
echo '{"tool_name":"Write","tool_input":{"file_path":"'$TEMP_DIR'/secret.txt"}}' | \
  CLAUDE_PROJECT_DIR="$TEMP_DIR" bun run "$TEMP_DIR/.claude/hooks/agentrc-runner.ts" 2>&1
echo "Exit code: $?"

rm -rf "$TEMP_DIR"

